class User(object):
    def __init__(self, name, role):
        self.name = name
        self.role = role  # basic/premium/enterprise

class Item(object):
    def __init__(self, name, price):
        self.name = name
        self.price = price

def calculate_discount(user, cart, payment_details):
    total = sum([item.price for item in cart])
    
    if user.role == 'enterprise':
        return total * 0.7   # 30% off
    elif user.role == 'premium':
        return total * 0.85  # 15% off
    else:
        return total         # no discount

def process_payment(user, cart, payment_details):
    total = calculate_discount(user, cart, payment_details)
    
    # logic to process payment goes here. Assuming it returns True if successful and False otherwise
    return (total > 0)  # for example purpose only

